// Generated by OrchestKit Claude Plugin
// Created: 2026-04-13

/**
 * Agent Watchdog - SubagentStop Hook
 * CC 2.1.98 Compliant: async, non-blocking
 *
 * On each agent completion, scans remaining active background agents
 * for timeout. Emits warnings at 5min and critical alerts at 10min.
 *
 * Uses context-gate's spawn log (subagent-spawns.jsonl) for timestamps.
 * Never blocks — informational only.
 */

import { existsSync, readFileSync } from 'node:fs';
import type { HookInput, HookResult, HookContext } from '../types.js';
import { outputSilentSuccess, getProjectDir } from '../lib/common.js';
import { NOOP_CTX } from '../lib/context.js';

const HOOK_NAME = 'agent-watchdog';
const WARNING_MS = 5 * 60 * 1000;   // 5 minutes
const CRITICAL_MS = 10 * 60 * 1000; // 10 minutes
// Hard age cap: spawns older than this are treated as zombies from prior
// sessions (terminal closed, OOM, kernel panic, /clear without graceful
// completion) and silently dropped from watchdog output. Without this,
// subagent-spawns.jsonl accumulates entries forever and watchdog spews
// CRITICAL warnings about agents that haven't existed for days. See #1882.
//
// Any agent legitimately running longer than 24h is hung in practice;
// the warning at that age serves no actionable purpose.
export const MAX_SPAWN_AGE_MS = 24 * 60 * 60 * 1000; // 24 hours

interface SpawnEntry {
  timestamp: string;
  agent_id?: string;
  subagent_type?: string;
  session_id?: string;
}

/**
 * Read recent spawn entries from context-gate's log
 */
function getActiveSpawns(): SpawnEntry[] {
  const logPath = `${getProjectDir()}/.claude/logs/subagent-spawns.jsonl`;
  if (!existsSync(logPath)) return [];

  try {
    const content = readFileSync(logPath, 'utf8');
    const lines = content.trim().split('\n').filter(Boolean);
    // Only check last 20 entries for performance
    const recentLines = lines.slice(-20);
    const entries: SpawnEntry[] = [];

    for (const line of recentLines) {
      try {
        entries.push(JSON.parse(line));
      } catch {
        // Skip invalid JSON
      }
    }

    return entries;
  } catch {
    return [];
  }
}

/**
 * Check for hung background agents and emit warnings
 */
export function agentWatchdog(input: HookInput, ctx: HookContext = NOOP_CTX): HookResult {
  const completedAgentId = input.agent_id;
  const currentSessionId = process.env.CLAUDE_SESSION_ID;
  const now = Date.now();

  const spawns = getActiveSpawns();
  if (spawns.length === 0) return outputSilentSuccess();

  // CC 2.1.145+: when CC ships an authoritative live-task list on Stop hook
  // input, treat IT as truth and drop spawn entries not in it. Cures the
  // 4-day-old phantom-agent CRITICAL noise the 24h cap was supposed to fix
  // but didn't (see #1882). On CC < 2.1.145, background_tasks is undefined
  // and we fall back to timestamp-based filtering only.
  const liveAgentIds = new Set<string>();
  const hasAuthoritative = Array.isArray(input.background_tasks);
  if (hasAuthoritative) {
    for (const task of input.background_tasks ?? []) {
      if (task.agent_id) liveAgentIds.add(task.agent_id);
    }
  }

  const warnings: string[] = [];

  for (const spawn of spawns) {
    // Skip the agent that just completed
    if (spawn.agent_id && spawn.agent_id === completedAgentId) continue;

    // CC 2.1.145+: drop spawns NOT in CC's authoritative live list.
    // If hasAuthoritative is true but spawn lacks agent_id, fall through to
    // the older timestamp/session checks rather than dropping blindly.
    if (hasAuthoritative && spawn.agent_id && !liveAgentIds.has(spawn.agent_id)) continue;

    // Session-scope filter: only warn about agents spawned in THIS session.
    // Cross-session zombies (terminal closed, OOM, /clear) are someone else's
    // problem and pollute output of the current session otherwise.
    // Spawns without a session_id are pre-filter entries — let the 24h cap
    // handle them.
    if (currentSessionId && spawn.session_id && spawn.session_id !== currentSessionId) continue;

    if (!spawn.timestamp) continue;
    const elapsed = now - new Date(spawn.timestamp).getTime();
    // Reap zombies: silently drop spawns older than the hard cap (see #1882).
    if (elapsed > MAX_SPAWN_AGE_MS) continue;
    const agentLabel = spawn.subagent_type || spawn.agent_id || 'unknown';

    if (elapsed >= CRITICAL_MS) {
      warnings.push(`CRITICAL: Agent "${agentLabel}" running for ${Math.round(elapsed / 60000)}min — may be hung. Consider Ctrl+F to force-stop.`);
      ctx.log(HOOK_NAME, `Critical timeout: ${agentLabel} (${Math.round(elapsed / 1000)}s)`, 'warn');
    } else if (elapsed >= WARNING_MS) {
      warnings.push(`WARNING: Agent "${agentLabel}" running for ${Math.round(elapsed / 60000)}min.`);
      ctx.log(HOOK_NAME, `Timeout warning: ${agentLabel} (${Math.round(elapsed / 1000)}s)`, 'debug');
    }
  }

  if (warnings.length > 0) {
    return {
      continue: true,
      systemMessage: `[Agent Watchdog] ${warnings.join(' | ')}`,
    };
  }

  return outputSilentSuccess();
}

export default agentWatchdog;
